local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("skillImage", function(inst)     TD.player(inst, function()                  local widget = inst[string.format("td1madao%sSkillEffectWidgets", inst.prefab or TD.CHAR)]         widget:SetClickable(false)         widget:Show()         widget:MoveToFront()                  local base_x = 1000         local base_y = 550         widget:SetTexture(string.format("images/%s_skill_effect.xml", inst.prefab or TD.CHAR), string.format("%s_skill_effect.tex", inst.prefab or TD.CHAR))         widget:SetPosition(base_x, base_y, 0)         widget:SetScale(4)                  local step = 0.05         local totalTime = 1.5         local num = totalTime / step         local alphaStep = 1 / math.floor(num)                  local calc = 1         TD.period(inst, nil, function()             widget:SetPosition(base_x - calc * 30, base_y, 0)             if calc < math.floor(num) then                 widget:SetFadeAlpha(alphaStep * calc)             else                 widget:SetFadeAlpha(1 - alphaStep * (calc - math.floor(num)))             end             calc = calc + 1         end, step, totalTime, function()             widget:Hide()         end)     end) end) TD.createFn("fixImg", function(widget)     if not widget then         return     end     if widget.SetVRegPoint then         widget:SetVRegPoint(_G.ANCHOR_BOTTOM)     end     if widget.SetHRegPoint then         widget:SetHRegPoint(_G.ANCHOR_LEFT)     end     if widget.SetVAnchor then         widget:SetVAnchor(_G.ANCHOR_BOTTOM)     end     if widget.SetHAnchor then         widget:SetHAnchor(_G.ANCHOR_LEFT)     end     if widget.SetScaleMode then         widget:SetScaleMode(_G.SCALEMODE_PROPORTIONAL)     end     if widget.SetHAlign then         widget:SetHAlign(_G.ANCHOR_LEFT)     end     if widget.SetVAlign then         widget:SetVAlign(_G.ANCHOR_BOTTOM)     end     if widget.inst and widget.inst.ImageWidget and widget.inst.ImageWidget.SetBlendMode and _G.BLENDMODE and _G.BLENDMODE.Premultiplied then         widget.inst.ImageWidget:SetBlendMode(_G.BLENDMODE.Premultiplied)     end end) TD.createFn("ensureWidget", function(inst, widgetName)     if inst and TD.isStr(widgetName) then                  inst["td1madao_prefab"] = widgetName         local name = "td1madaoEnsureWidgetTask"         if inst and inst.replica.container and inst.replica.container.WidgetSetup and inst.replica.container.widget ~= nil then             return         end         TD.period(inst, name, function()             if inst and inst.replica.container and inst.replica.container.WidgetSetup and inst.replica.container.widget == nil then                 inst.replica.container:WidgetSetup(widgetName)                 TD.removeTask(inst, name)                 TD.removeTask(inst, name .. "Cleaner")             end         end, 0.05, 3)     end end) TD.createFn("addScreen", function(screen, tag)     if not screen then         return     end     if not TD.G.windowArray then         TD.G.windowArray = {}     end     TD.fori(TD.G.windowArray, function(k, v)         TD.safePopScreen(v)     end)          TD.G.windowArray = {}     screen.SCREENTAG = tag or screen.name     local hasScreen = false     TD.fori(_G.TheFrontEnd.screenstack or {}, function(k, v)         if v and v.SCREENTAG and v.SCREENTAG == screen.SCREENTAG then             hasScreen = true             return true         end     end)     if not hasScreen then         _G.TheFrontEnd:PushScreen(screen)                  if not TD.G.windowArray then             TD.G.windowArray = {}         end         table.insert(TD.G.windowArray, screen)     end end) TD.createFn("popScreen", function(screen)     if not screen then         _G.TheFrontEnd:PopScreen()         return     end     local closed = false     for i = 1, #TD.G.windowArray do         local wind = TD.G.windowArray[i]         if wind and wind == screen and not wind.td1madao_this_window_closed then             TD.G.windowArray[i] = false                          wind.td1madao_this_window_closed = true             if wind.Close then                 wind:Close()             else                 _G.TheFrontEnd:PopScreen(wind)             end             closed = true             break         end     end     if not closed then         _G.TheFrontEnd:PopScreen(screen)     end end) TD.createFn("safePopScreen", function(screen)     local closed = false     for i = 1, #TD.G.windowArray do         local wind = TD.G.windowArray[i]         if wind and wind == screen and not wind.td1madao_this_window_closed then             TD.G.windowArray[i] = false                          wind.td1madao_this_window_closed = true             if wind.Close then                 wind:Close()             else                 _G.TheFrontEnd:PopScreen(wind)             end             closed = true             break         end     end end) TD.createFn("cleanWind", function()     if not TD.G.windowArray then         TD.G.windowArray = {}     end     for i = 1, #TD.G.windowArray do         local wind = TD.G.windowArray[i]         if wind and not wind.td1madao_this_window_closed then             wind.td1madao_this_window_closed = true             if wind.Close then                 wind:Close()             else                 _G.TheFrontEnd:PopScreen(wind)             end         end     end     TD.G.windowArray = {} end) local bigpopupdialog = require("screens/bigpopupdialog") TD.createFn("createBigWindow", function(player, title, content, buttons)          if TD.isPlayer(player) then         local mywindow = bigpopupdialog(title, content, {             buttons or {                 text = TD.showStr("好的", "Ok"),                 cb = function()                     TD.popScreen()                 end             }         })         TD.addScreen(mywindow)         mywindow.bg:SetSize(500, 400)         mywindow.bg.fill:SetSize(1000, 700)         mywindow.title:SetPosition(0, 200, 0)         mywindow.text:SetRegionSize(900, 500)         mywindow.menu:SetPosition(mywindow.menu:GetPosition().x, -180, 0)     end end) 